* {{ill|Anesaki Futagozuka Kofun|lt=Anegasaki Kofun Cluster|ja|姉崎古墳群|qq=|qq=draft|qq=draft|qq=draft|qq=draft|qq=draft|qq=draft|12=simple|13=User:Immanuelle/Anesaki Futagozuka Kofun|qq=}} ([[:en:Ichihara, Chiba|Ichihara, Chiba]], [[:en:Chiba Prefecture|Chiba Prefecture]])
